var e=JSON.parse(`[{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"동결되어 있는 동안 수없이 많은 꿈을 꿔 왔다.","JPN":"凍結されている間、いくつもの夢を見てきた。","ENG":"I had countless dreams while I was frozen asleep.","TWN":"在冰凍的歲月裡，我做過無數個夢"},"stage":{"bg":"VARUNA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"새까만 그림자들이 나를 향해 손가락질하고, 원망하는 꿈.","JPN":"真っ黒な影が私を指さし、恨みを向けてくる夢。","ENG":"One was a dream of resentment where pitch-black shadows would blame me.","TWN":"夢裡有許多黑影對著我指指點點，埋怨我。"},"stage":{"bg":"VARUNA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"도망치려 해도 깊은 늪처럼 나를 끌어당기는 그림자들은, 끝내 나를 놔주지 않았다.","JPN":"逃げようとしても深い沼のように私を引き寄せる影たちは、最後まで私を放そうとはしなかった。","ENG":"No matter how much I tried to run away, they kept pulling me in closer like a deep swamp, and never let me go.","TWN":"即使試圖逃跑，那些黑影也沒有放過我，將我一點一點拉回深淵。"},"stage":{"bg":"VARUNA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"몸은 잠들어 있었지만, 정신은 늘 깨어 있었고, 눈을 뜬 뒤에야 깨달았다.","JPN":"身体は眠っていたが、意識はずっとはっきりしていて、目を覚ました後になって気づいた。","ENG":"My body was asleep, but my mind was wide awake. And I only realized it after I opened my eyes.","TWN":"身體雖然沉睡，然而意識卻很清醒。"},"stage":{"bg":"VARUNA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"나는 전우들을 잊은 죄로 지옥에 떨어졌다는 것을.","JPN":"私は戦友たちを忘れた罪で地獄に落ちたということを。","ENG":"I realized that I had fallen into hell for the sin of forgetting my comrades.","TWN":"睜開眼後，我才意識到，"},"stage":{"bg":"VARUNA_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"전우들을 잊고, 지켜야 할 것들을 지키지 못한 죄라…….","JPN":"戦友たちを忘れ、守るべきものを守れなかった罪……","ENG":"A sin of forgetting my comrades and not being able to protect what I should've...","TWN":"我是因遺棄戰友之罪而墜入地獄的。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"어쩌면 이 현실이, 나에겐 제일 어울리는 형벌일지도 모르겠어.","JPN":"もしかしたらこの現実が、私に与えられた罰なのかもしれない。","ENG":"Maybe this reality is the punishment that suited me the best.","TWN":"或許這個現實，對我來說是最合適的懲罰。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"나는 아직도…… 날 원망하는 너희들의 이름을 떠올리지 못하고 있으니까.","JPN":"私はまだ……私を恨む君たちの名前すら思い出せないんだから。","ENG":"Because I still... can't recall the names of those who blame me.","TWN":"我依然……記不起那些恨我之人的名字。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"너도 그렇게 생각하고 있지 않나?","JPN":"君もそう思っているだろう？","ENG":"Don't you think so too?","TWN":"你也是這麼想的吧？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"네가 나타날 것이라 예상하고 있었다.","JPN":"君が現れることはわかっていた。","ENG":"I was expecting you'd show up.","TWN":"我有預料到你會出現。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"넌 과거의 나와 무슨 관계지?","JPN":"君は過去の私とはどういう関係だ？","ENG":"How do you know my past self?","TWN":"你和過去的我是什麼關係？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"벌써 거기까지 추측하신 겁니까?","JPN":"もうそこまで予想がついているのですか？","ENG":"Have you already guessed that far?","TWN":"竟然已經整理出這麼多嗎？"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"역시 아디트야군요.","JPN":"さすがアーディティヤですね。","ENG":"You must really be Aditya.","TWN":"不愧是阿迪亞。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"날 원하는 이유를 말해라. 그리고 왜 이제와서 그 뻔뻔한 면상을 들이미는지도.","JPN":"私に何を求めている。今更その厚かましい面を、再び現した理由はなんだ。","ENG":"Tell me why you want me, and why you are now brazenly showing your face.","TWN":"告訴我你找我的理由，還有為什麼現在才厚著臉皮出現。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":null,"C":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"당신 혼자서는 아무것도 할 수 없다는 것을 상기시켜주고 싶었습니다.","JPN":"あなた一人では何もできないということを、思い出させてあげたかった。","ENG":"I wanted to remind you that you can't do anything alone.","TWN":"我只是想提醒你，你一個人是很有限的。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"그리고 역시나…… 우리가 아니면 당신은 혼자일 수밖에 없군요.","JPN":"それにやっぱり……我々がいなければ、あなたは一人になるしかない。","ENG":"And, as expected... that you will be alone without us.","TWN":"而且……如果沒有我們，你就只能能是一個人。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"}}}},{"id":"L33_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"나에게 살려달라 울부짖던 동료들, 그리고 아샤, 그리고 침식체.","JPN":"私に助けてくれと泣き叫んだ仲間たち、アーシャ、侵食体。","ENG":"The cries of my comrades, begging me to save them. Asha, and the C.O.","TWN":"向我哭喊求救的戰友，還有阿莎，還有侵蝕體。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그것이 너와 관련이 없다고 생각하기가 어렵군.","JPN":"それらが君と無関係とは思えない。","ENG":"It's hard to believe that they have nothing to do with me.","TWN":"很難認為這一切與我無關。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"}}}},{"id":"L36_1","type":"dialog","speaker":"ROBE_VARUNA_NPC_ADITYA","text":{"KOREA":"그러니 다시 묻겠다. 날 원하는 이유를 말해라.","JPN":"だから、もう一度聞く。私に何を求める。","ENG":"So, I will ask again. Why do you want me?","TWN":"那麼，我再問你一次。你找我是要做什麼。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_PRIDE"}}}},{"id":"L38_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"카운터가 된 후 사막을 떠돌던 저에게, 당신은 라비라는 새 이름을 지어주셨죠.","JPN":"カウンターになり、砂漠を彷徨っていた私に、あなたはラビという新しい名前を授けてくださいました。","ENG":"You gave me a new name, Ravi, when I was wandering the desert after becoming a Counter.","TWN":"在我成為制裁者，徘徊於沙漠之時，拉維，這個名字是你替我取的。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"당신의 믿음직한 동료이자, 당신의 불꽃입니다.","JPN":"あなたにとって信頼のおける仲間であり、あなたの炎です。","ENG":"I was your trusty comrade and your flame.","TWN":"我是你值得信賴的夥伴，也是你的火焰。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"앞으로도 당신의 곁에서, 영원히 당신과 함께하기 위해 우리를 대표해 모습을 드러낸겁니다.","JPN":"これからもあなたのそばで、永遠にあなたと行動をともにするために、我々を代表する者として、私が来たのです。","ENG":"I have appeared in front of you on behalf of everyone who wishes to be by your side forever.","TWN":"今後也會在你身邊，永遠與你在一起，我代表大家出現在這裡。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_LAUGH"}}}},{"id":"L41_1","type":"dialog","speaker":"LAVI_VARUNA_NPC_AHAB","text":{"KOREA":"다른 동료들도 기다리고 있거든요. 당신을.","JPN":"他の仲間たちも待っているのです、あなたを。","ENG":"Everyone else is waiting for you.","TWN":"其他同伴也在一直等著你。"},"stage":{"bg":"COUNTRYROAD","slots":{"L":{"char_id":"ROBE_VARUNA_NPC_ADITYA","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAVI_VARUNA_NPC_AHAB","face":"UNIT_IDLE"}}}}]`);export{e as default};